    // Async command methods

    /// <summary>Send PowerAdjustRequest command (0x0000).</summary>
    public Task<InvokeResponse> PowerAdjustRequestAsync(
        ulong power,
        uint duration,
        AdjustmentCauseEnum cause,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv =>
        {
            tlv.AddUInt64(0, power);
            tlv.AddUInt32(1, duration);
            tlv.AddUInt8(2, (byte)cause);
        }, ct);

    /// <summary>Send CancelPowerAdjustRequest command (0x0001).</summary>
    public Task<InvokeResponse> CancelPowerAdjustRequestAsync(CancellationToken ct = default)
        => InvokeCommandAsync(0x0001, ct: ct);

    /// <summary>Send StartTimeAdjustRequest command (0x0002).</summary>
    public Task<InvokeResponse> StartTimeAdjustRequestAsync(
        uint requestedStartTime,
        AdjustmentCauseEnum cause,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0002, tlv =>
        {
            tlv.AddUInt32(0, requestedStartTime);
            tlv.AddUInt8(1, (byte)cause);
        }, ct);

    /// <summary>Send PauseRequest command (0x0003).</summary>
    public Task<InvokeResponse> PauseRequestAsync(
        uint duration,
        AdjustmentCauseEnum cause,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0003, tlv =>
        {
            tlv.AddUInt32(0, duration);
            tlv.AddUInt8(1, (byte)cause);
        }, ct);

    /// <summary>Send ResumeRequest command (0x0004).</summary>
    public Task<InvokeResponse> ResumeRequestAsync(CancellationToken ct = default)
        => InvokeCommandAsync(0x0004, ct: ct);

    /// <summary>Send ModifyForecastRequest command (0x0005).</summary>
    public Task<InvokeResponse> ModifyForecastRequestAsync(
        uint forecastID,
        SlotAdjustmentStruct[] slotAdjustments,
        AdjustmentCauseEnum cause,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0005, tlv =>
        {
            tlv.AddUInt32(0, forecastID);
            if (slotAdjustments != null) { tlv.AddArray(1); foreach (var item in slotAdjustments) { WriteSlotAdjustmentStruct(tlv, item); } tlv.EndContainer(); }
            tlv.AddUInt8(2, (byte)cause);
        }, ct);

    /// <summary>Send RequestConstraintBasedForecast command (0x0006).</summary>
    public Task<InvokeResponse> RequestConstraintBasedForecastAsync(
        ConstraintsStruct[] constraints,
        AdjustmentCauseEnum cause,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0006, tlv =>
        {
            if (constraints != null) { tlv.AddArray(0); foreach (var item in constraints) { WriteConstraintsStruct(tlv, item); } tlv.EndContainer(); }
            tlv.AddUInt8(1, (byte)cause);
        }, ct);

    /// <summary>Send CancelRequest command (0x0007).</summary>
    public Task<InvokeResponse> CancelRequestAsync(CancellationToken ct = default)
        => InvokeCommandAsync(0x0007, ct: ct);

